<template>
  <div 
    class="mask"
    @mouseup="moveend"
  >
    <div
      class="container"
      ref="container"
    >
      <div class="clip">
        <div class="img">
          <img 
            :src="imgSrc"
            class="preview_img"
          >
          <div class="img_mask" />
          <img 
            :src="imgSrc"
            class="preview_img_first"
            draggable="false"
            @mousedown="moveStart"
            @mousemove="move"
          >
        </div>
      </div>
      <span 
        class="con"
        @click="clipImg"
      >确定</span>
      <span 
        class="cancel"
        @click="$emit('cancelMaskShow')"
      >取消</span>
    </div>
  </div>
</template>
<script>
export default {
    data (){
        return {
            top:60,
            right:60,
            bottom:60,
            left:60,
            startX:0,
            startY:0,
            endX:0,
            endY:0,
            distanceX:0,
            distanceY:0,
            isDown:false,
            // 图片裁剪宽高
            imgWidth:180,
            imgHeight:180

        };

    },
    props:{
        imgSrc:{
            type:String,
            default:""
        }
    },
    methods:{
        moveStart (event){
            this.startX = event.clientX;
            this.startY = event.clientY;
            this.isDown = true;

        },
        // 图片裁剪
        clipRange(direction){
            if(direction <= 0){
                direction = 0;
            }else if(direction >= 60 * 2){
                // 60 为clip的高度
                direction = 60 * 2;
            }
            return direction;

        },
        move(event){
            if(!this.isDown){
                return;
            }
            this.endX = event.clientX,
            this.endY = event.clientY;
            this.distanceX = this.endX - this.startX,
            this.distanceY = this.endY - this.startY;
    
            event.target.style.clipPath = `inset(${this.clipRange(this.distanceY + this.top) }px ${ this.clipRange(this.right - this.distanceX)}px ${ this.clipRange(this.bottom - this.distanceY) }px ${this.clipRange(this.left + this.distanceX)}px)`;
            

        },
        moveend(){
            this.isDown = false;
            this.top = this.clipRange(this.distanceY + this.top);
            this.right = this.clipRange(this.right - this.distanceX);
            this.bottom = this.clipRange(this.bottom - this.distanceY);
            this.left = this.clipRange(this.left + this.distanceX);

        },
        // 裁剪图片
        clipImg(){
            const _self = this;
            this.$emit("clip",{
                left:_self.left,
                top:_self.top,
                imgWidth:_self.imgWidth,
                imgHeight:_self.imgHeight
            });
            this.$emit("cancelMaskShow");

        }
    }
    
};
</script>
<style lang="scss" scoped>
.mask{
    width:100%;
    height:205vh;
    position:absolute;
    top:0;
    left:0;
    z-index:9999;
    background:rgba(112,112,112,0.5);
    .container{
        position:relative;
        top:40px;
        left:130px;
        height:350px;
        background-color:rgb(137,137,137);
        display:inline-block;
        .clip{
            width: 300px;
            height:300px;
            border:1px dotted rgb(49,49,49);
             user-select: none;
            .img{
                position:relative;
                .preview_img{
                width:300px;
                height:300px;
                user-select: none;
                }
                .img_mask{
                    position: absolute;
                    top:0;
                    left:0;
                    z-index:9999;
                    width:300px;
                    height:300px;
                    background-color:rgba(170,170,170,0.6);
                }
                .preview_img_first{
                    @extend .preview_img;
                    position: absolute;
                    top:0;
                    left:0;
                    z-index:999999;
                    cursor: move;
                    clip-path:inset(60px 60px 60px 60px);
                }

            }
            
        }
        .con,.cancel{
            padding:5px 10px;
            background-color:rgb(89,73,63);
            border-radius:6px;
            position:absolute;
            bottom:8px;
            cursor: pointer;
            &:hover{
                color:rgb(170,170,170);
            }
            
            }
        .con{
            left:30px;
        }
        .cancel{
            left:200px;
        }
        
    }

}

</style>

